import { ElementType } from 'react';
import { Paths } from 'type-fest';
import {
  AlphanumericFilterPopup,
  DateFilterDropdown,
  MultiFilterDropdown,
  RemoteMultiFilterDropdown,
} from './FilterDropdowns';
import { looseGetValueFromPath } from './selectors/QHGridSelector';
import { ObjectLiteral } from './types';

export type FilterValue = string | number | null | undefined;

const filterValuesSetMap = new WeakMap<FilterValue[], Set<FilterValue>>();

function multiFilterFilter<Data extends ObjectLiteral = object>(
  item: Data,
  filterField: Paths<Data> | string,
  filterValues: FilterValue[] | undefined
) {
  if (!filterValues || filterValues.length === 0) {
    return true;
  }
  let set = filterValuesSetMap.get(filterValues);
  if (!set) {
    set = new Set(filterValues);
    filterValuesSetMap.set(filterValues, set);
  }
  const itemFieldValues = looseGetValueFromPath(item, filterField);
  if (Array.isArray(itemFieldValues)) {
    return itemFieldValues.some((itemValue) => set!.has(itemValue));
  }
  return set!.has(itemFieldValues);
}

export const filterTypes: {
  [filterType in string]: {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    filter: (item: any, filterField: string, filterValues: any) => boolean;
    component: ElementType;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    props?: Record<string, any>;
  };
} = {
  multiFilter: {
    filter: multiFilterFilter,
    component: MultiFilterDropdown,
  },
  remoteMultiFilter: {
    filter: multiFilterFilter,
    component: RemoteMultiFilterDropdown,
  },
  dateFilter: {
    filter: (
      item,
      filterField,
      filterValues: { startDate: string; endDate: string }
    ) => {
      if (!filterValues) {
        return true;
      }
      const { startDate, endDate } = filterValues;
      const value = looseGetValueFromPath(item, filterField);
      if (value == null) {
        return false;
      }
      const date = new Date(value).toISOString().slice(0, 10);
      if (startDate && date <= new Date(startDate).toISOString().slice(0, 10)) {
        return false;
      }
      if (endDate && date >= new Date(endDate).toISOString().slice(0, 10)) {
        return false;
      }
      return true;
    },
    component: DateFilterDropdown,
  },
  numericFilter: {
    filter: comparisonFilter(numericComparisonFilter),
    component: AlphanumericFilterPopup,
    props: {
      filterSubType: 'numeric',
    },
  },
  alphanumericFilter: {
    filter: comparisonFilter(alphanumericComparisonFilter),
    component: AlphanumericFilterPopup,
    props: {
      filterSubType: 'alphanumeric',
    },
  },
};
const singleComparators = {
  null: true,
  '!null': true,
  empty: true,
  '!empty': true,
};
function comparisonFilter(comparisons) {
  return (item, filterField, filterValues) => {
    if (!filterValues) return true;
    let isValid = true;
    let orHasValue = false;
    for (const opts of filterValues) {
      if (opts.combination === '||') {
        if (isValid && orHasValue) break;
        isValid = true;
        orHasValue = false;
      } else if (isValid === false) {
        continue;
      }
      if (!(singleComparators[opts.comparison] || opts.value)) {
        continue;
      }
      orHasValue = true;
      if (
        !comparisons(
          opts.comparison,
          looseGetValueFromPath(item, filterField),
          opts.value
        )
      ) {
        isValid = false;
      }
    }
    return orHasValue && isValid;
  };
}
function numericComparisonFilter(comparison, a, b) {
  switch (comparison) {
    case '=':
      return a == b;
    case '!=':
      return a != b;
    case '>=':
      return a >= b;
    case '>':
      return a > b;
    case '<=':
      return a <= b;
    case '<':
      return a < b;
    case 'null':
      return a == null;
    case '!null':
      return a != null;
    default:
      return true;
  }
}

function alphanumericComparisonFilter(comparison, a, b) {
  const stringA = String(a).toUpperCase();
  const stringB = String(b).toUpperCase();
  switch (comparison) {
    case '=':
      return stringA === stringB;
    case '!=':
      return stringA !== stringB;
    case 'contains':
      return stringA.includes(stringB);
    case '!contains':
      return !stringA.includes(stringB);
    case 'starts':
      return stringA.startsWith(stringB);
    case 'ends':
      return stringA.endsWith(stringB);
    case 'null':
      return a == null;
    case '!null':
      return a != null;
    case 'empty':
      return stringA === '';
    case '!empty':
      return stringA !== '';
    default:
      return true;
  }
}
