import { QButton } from './Button';
import { QButtonGroup } from './ButtonGroup';

export interface PaginationProps {
  activePage: number;
  totalPages: number;
  onPageChange: (page: number) => void;
  /**
   * @default 3
   */
  numPageButtons?: number;
}
export function Pagination({
  activePage,
  onPageChange,
  totalPages,
  numPageButtons = 3,
}: PaginationProps) {
  const start = Math.min(
    Math.max(1, activePage - Math.floor(numPageButtons / 2)),
    Math.max(1, totalPages - numPageButtons + 1)
  );
  const end = Math.min(totalPages, start + numPageButtons - 1);
  const pageButtons = new Array(end - start + 1).fill(null).map((_, idx) => {
    const page = start + idx;
    return (
      <QButton
        key={page}
        onClick={() => onPageChange(page)}
        className={`qh-pagination--page ${page === activePage ? 'active' : ''}`}
      >
        {page}
      </QButton>
    );
  });
  return (
    <div className="qh-pagination">
      <QButtonGroup>
        <QButton onClick={() => onPageChange(1)}>«</QButton>
        <QButton
          onClick={() => onPageChange(Math.max(1, activePage - 1))}
          className="qh-pagination--prev"
        >
          ⟨
        </QButton>
        {pageButtons}
        <QButton
          onClick={() => onPageChange(Math.min(totalPages, activePage + 1))}
          className="qh-pagination--next"
        >
          ⟩
        </QButton>
        <QButton onClick={() => onPageChange(totalPages)}>»</QButton>
      </QButtonGroup>
    </div>
  );
}
