import { FilterValue } from '../FilterTypeConfig';
import { MFBaseProps } from '../types';

export function getAccessorValue(
  opt: FilterValue,
  accessor: MFBaseProps['accessor']
) {
  if (accessor == null) {
    return opt;
  }
  switch (typeof accessor) {
    case 'function':
      return accessor(opt);
    case 'object':
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      return accessor[opt as any];
    case 'number':
    case 'string':
      // This probably shouldn't even exist here...
      return opt?.[accessor];
    default:
      return undefined;
  }
}

export enum Comparisons {
  equals = '=',
  notEquals = '!=',
  greaterOrEqual = '>=',
  greater = '>',
  lessOrEqual = '<=',
  less = '<',
  null = 'null',
  notNull = '!null',
  contains = 'contains',
  notContains = '!contains',
  starts = 'starts',
  ends = 'ends',
  empty = 'empty',
  notEmpty = '!empty',
}

export enum Combinations {
  and = '&&',
  or = '||',
}
export interface AlphanumericOpt {
  comparison: Comparisons;
  combination: Combinations;
  value: string;
}

