import {
  useFloating,
  autoUpdate,
  offset,
  flip,
  shift,
  useClick,
  useDismiss,
  useRole,
  useInteractions,
  useMergeRefs,
  Placement,
  FloatingPortal,
  FloatingFocusManager,
  useId,
  size,
  useHover,
  useFocus,
} from '@floating-ui/react';
import {
  ButtonHTMLAttributes,
  cloneElement,
  createContext,
  Dispatch,
  forwardRef,
  HTMLProps,
  isValidElement,
  ReactNode,
  SetStateAction,
  useCallback,
  useContext,
  useLayoutEffect,
  useMemo,
  useState,
} from 'react';
import { QButton, QButtonProps } from './Button';
import clsx from 'clsx';
import { QIcon } from './Icon';

export interface QPopoverOptions {
  initialOpen?: boolean;
  placement?: Placement;
  modal?: boolean;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  /**
   * Acts as a tooltip - it will work on hover/focus and light dismissals instead of requiring clicks.
   * This is useful for tooltips that are not meant to be interactive.
   * @default false
   */
  tooltip?: boolean;
  /**
   * If true, the popover will not close when clicking outside of it or pressing escape.
   * This is useful for modals or other interactive content that should not be dismissed easily.
   * @default false
   */
  persistent?: boolean;
}

export function usePopover({
  initialOpen = false,
  placement = 'bottom',
  modal,
  open: controlledOpen,
  onOpenChange: setControlledOpen,
  tooltip = false,
  persistent = false,
}: QPopoverOptions = {}) {
  const [uncontrolledOpen, setUncontrolledOpen] = useState(initialOpen);
  const [labelId, setLabelId] = useState<string | undefined>();
  const [descriptionId, setDescriptionId] = useState<string | undefined>();

  const open = controlledOpen ?? uncontrolledOpen;
  const setOpen = useCallback(
    (open: boolean) => {
      setControlledOpen?.(open);
      setUncontrolledOpen(open);
    },
    [setControlledOpen]
  );
  const [availableHeight, setAvailableHeight] = useState<number | undefined>(
    undefined
  );

  const data = useFloating({
    placement,
    open,
    onOpenChange: setOpen,
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(5),
      flip({
        crossAxis: placement.includes('-'),
        fallbackAxisSideDirection: 'end',
        padding: 5,
      }),
      shift({ padding: 5 }),
      size({
        apply({ availableHeight }) {
          setAvailableHeight(availableHeight);
        },
      }),
    ],
  });

  const context = data.context;

  const click = useClick(context, {
    enabled: !tooltip && controlledOpen == null,
  });
  const hover = useHover(context, {
    move: false,
    enabled: tooltip && controlledOpen == null,
  });
  const focus = useFocus(context, {
    enabled: tooltip && controlledOpen == null,
  });
  const dismiss = useDismiss(context, { enabled: !persistent });
  const role = useRole(context, { role: tooltip ? 'tooltip' : 'dialog' });

  const interactions = useInteractions([hover, focus, click, dismiss, role]);

  return useMemo(
    () => ({
      open,
      setOpen,
      ...interactions,
      ...data,
      modal,
      labelId,
      descriptionId,
      setLabelId,
      setDescriptionId,
      availableHeight,
      tooltip,
    }),
    [
      open,
      setOpen,
      interactions,
      data,
      modal,
      labelId,
      descriptionId,
      availableHeight,
      tooltip,
    ]
  );
}

type ContextType =
  | (ReturnType<typeof usePopover> & {
      setLabelId: Dispatch<SetStateAction<string | undefined>>;
      setDescriptionId: Dispatch<SetStateAction<string | undefined>>;
      availableHeight?: number;
    })
  | null;

const PopoverContext = createContext<ContextType>(null);

export const usePopoverContext = () => {
  const context = useContext(PopoverContext);

  if (context == null) {
    throw new Error('Popover components must be wrapped in <Popover />');
  }

  return context;
};

export interface QPopoverProps extends QPopoverOptions {
  children: ReactNode;
}

/**
 * A Popover is a floating element that can be used to display content either interactively or as a tooltip.
 *
 * @example
 * ```tsx
 * <QPopover>
 *  <QPopoverTrigger>Open Popover</QPopoverTrigger>
 *  <QPopoverContent>
 *    <QPopoverHeading>Popover Heading</QPopoverHeading>
 *   <QPopoverDescription>Popover Description</QPopoverDescription>
 *   <QPopoverClose />
 *   <p>Popover Content</p>
 *  </QPopoverContent>
 * </QPopover>
 * ```
 */
export function QPopover({
  children,
  modal = false,
  ...restOptions
}: QPopoverProps) {
  // This can accept any props as options, e.g. `placement`,
  // or other positioning options.
  const popover = usePopover({ modal, ...restOptions });
  return (
    <PopoverContext.Provider value={popover}>
      {children}
    </PopoverContext.Provider>
  );
}

export interface QPopoverTriggerProps {
  children: ReactNode;
  /**
   * If true, this will render the trigger as the children without a wrapper element.
   * This is useful for when you want to use a custom element as the trigger.
   */
  asChild?: boolean;
}

/**
 * The trigger for a Popover. This is the element that will be used to
 * open the popover.
 *
 * If the Popover is controlled, then this will need an `onClick` handler to toggle the popover.
 * as the trigger won't toggle by itself for controlled popovers.
 */
export const QPopoverTrigger = forwardRef<
  HTMLElement,
  QButtonProps & QPopoverTriggerProps
>(function PopoverTrigger(
  { children, asChild = false, size, ...props },
  propRef
) {
  const context = usePopoverContext();
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const childrenRef = (children as any).ref;
  const ref = useMergeRefs([context.refs.setReference, propRef, childrenRef]);

  // `asChild` allows the user to pass any element as the anchor
  if (asChild && isValidElement(children)) {
    return cloneElement(
      children,
      context.getReferenceProps({
        ref,
        ...props,
        ...(children.props as Record<string, unknown>),
        ...{ 'data-state': context.open ? 'open' : 'closed' },
      })
    );
  }

  return (
    <QButton
      ref={ref}
      type="button"
      // The user can style the trigger based on the state
      data-state={context.open ? 'open' : 'closed'}
      {...context.getReferenceProps(props)}
      active={context.open}
      size={size}
    >
      {children}
    </QButton>
  );
});

/**
 * The content for a Popover. This renders the popover itself.
 */
export const QPopoverContent = forwardRef<
  HTMLDivElement,
  HTMLProps<HTMLDivElement>
>(function PopoverContent({ style, ...props }, propRef) {
  const {
    context: floatingContext,
    availableHeight,
    tooltip,
    ...context
  } = usePopoverContext();
  const ref = useMergeRefs([context.refs.setFloating, propRef]);

  if (!floatingContext.open) return null;

  return (
    <FloatingPortal>
      <FloatingFocusManager
        context={floatingContext}
        modal={context.modal}
        disabled={tooltip}
      >
        <div
          ref={ref}
          style={{
            ...context.floatingStyles,
            '--availableHeight': availableHeight,
            ...style,
          }}
          aria-labelledby={context.labelId}
          aria-describedby={context.descriptionId}
          {...context.getFloatingProps(props)}
          className={clsx('qh-root qh-popover', props.className)}
        >
          {props.children}
        </div>
      </FloatingFocusManager>
    </FloatingPortal>
  );
});

/**
 * Sets the `aria-labelledby` attribute on the Popover root element to this.
 */
export const QPopoverHeading = forwardRef<
  HTMLHeadingElement,
  HTMLProps<HTMLHeadingElement>
>(function PopoverHeading(props, ref) {
  const { setLabelId } = usePopoverContext();
  const id = useId();

  // Only sets `aria-labelledby` on the Popover root element
  // if this component is mounted inside it.
  useLayoutEffect(() => {
    setLabelId(id);
    return () => setLabelId(undefined);
  }, [id, setLabelId]);

  return (
    <h2
      {...props}
      className={clsx(props.className, 'qh-popover-heading')}
      ref={ref}
      id={id}
    >
      {props.children}
    </h2>
  );
});

/**
 * Sets the `aria-describedby` attribute on the Popover root element to this.
 */
export const QPopoverDescription = forwardRef<
  HTMLParagraphElement,
  HTMLProps<HTMLParagraphElement>
>(function PopoverDescription(props, ref) {
  const { setDescriptionId } = usePopoverContext();
  const id = useId();

  // Only sets `aria-describedby` on the Popover root element
  // if this component is mounted inside it.
  useLayoutEffect(() => {
    setDescriptionId(id);
    return () => setDescriptionId(undefined);
  }, [id, setDescriptionId]);

  return (
    <p
      {...props}
      className={clsx(props.className, 'qh-popover-description')}
      ref={ref}
      id={id}
    />
  );
});

/**
 * Renders a close button for the popover that closes on click.
 */
export const QPopoverClose = forwardRef<
  HTMLButtonElement,
  ButtonHTMLAttributes<HTMLButtonElement>
>(function PopoverClose(props, ref) {
  const { setOpen } = usePopoverContext();
  const children = props.children ?? <QIcon name="close" />;
  return (
    <QButton
      type="button"
      ref={ref}
      variant="ghost"
      size="mini"
      compact
      aria-label="Close"
      {...props}
      className={clsx(props.className, 'qh-popover-close')}
      onClick={(event) => {
        props.onClick?.(event);
        setOpen(false);
      }}
    >
      {children}
    </QButton>
  );
});
