import dayjs from 'dayjs';
import { ReactNode } from 'react';

import { Get, IfAny, Paths } from 'type-fest';
import { ColumnConfig, ObjectLiteral } from '../types';

export function getTemplate(column) {
  if (column.template) {
    return column.template;
  }
  if (typeMap[column.type]) {
    return typeMap[column.type].template;
  }
  return undefined;
}
export function getExportTemplate<Data extends ObjectLiteral, ATI>(
  column: ColumnConfig<Data, ATI>
): ColumnConfig<Data, ATI>['exportTemplate'] | undefined {
  if (column.exportTemplate) {
    return column.exportTemplate;
  }
  return typeMap[column.type ?? '']?.exportTemplate;
  // if (column.type && typeMap[column.type]) {
  //   return typeMap[column.type].exportTemplate;
  // }
  // return undefined;
}

export function getValueFromPath<
  Data extends ObjectLiteral,
  Path extends Paths<Data>,
>(item: Data, path: Path): Path extends string ? Get<Data, Path> : Data[Path] {
  if (typeof path === 'number') {
    return item[path];
  }
  for (const key of path.split('.')) {
    if (key === '__proto__') {
      throw new Error('Invalid path');
    }
    if (item == null) return item;
    item = item[key];
  }
  return item as any;
}
export const looseGetValueFromPath = getValueFromPath as (
  data: any,
  field: any
) => any;

function getFieldValueBase<Data extends ObjectLiteral>(
  item: Data,
  accessor:
    | ((item: Data, field: Paths<Data>) => any)
    | object
    | Paths<Data>
    | undefined,
  fieldName: Paths<Data>
) {
  switch (typeof accessor) {
    case 'function':
      return accessor(item, fieldName);
    case 'object': {
      const value = getValueFromPath(item, fieldName);
      return accessor[String(value)];
    }
    default:
      return getValueFromPath(item, accessor || fieldName);
  }
}
function getFieldValueCurried<Data extends ObjectLiteral>(
  accessor:
    | ((item: Data, field: Paths<Data>) => any)
    | object
    | Paths<Data>
    | undefined,
  fieldName: Paths<Data>
): (item: Data) => any {
  switch (typeof accessor) {
    case 'function':
      return (item) => accessor(item, fieldName);
    case 'object': {
      return (item) => {
        const value = getValueFromPath(item, fieldName);
        return accessor[String(value)];
      };
    }
    default:
      return (item) => {
        const value = getValueFromPath(item, accessor || fieldName);
        if (Array.isArray(value)) return value[0]?.toString();
        return value;
      };
  }
}

export function getFieldValue<Data extends ObjectLiteral, ATI>(
  item: Data,
  field: ColumnConfig<Data, ATI>['field'],
  type?: ColumnConfig<Data, ATI>['type']
): Data[keyof Data] | any {
  let fieldName: Paths<Data>;
  let accessor: object | Paths<Data> | (typeof typeMap)['']['accessor'] =
    typeMap[type || '']?.accessor;
  if (typeof field === 'object') {
    fieldName = field.field;
    if (field.accessor) accessor = field.accessor;
  } else {
    fieldName = field;
  }
  return getFieldValueBase(item, accessor, fieldName);
}

export function getField<Data extends ObjectLiteral, ATI>(
  field: ColumnConfig<Data, ATI>['field']
) {
  if (field === null) return field;
  switch (typeof field) {
    case 'object':
      return field.field;
    default:
      return field;
  }
}
export const typeMap: Record<
  string,
  {
    accessor?: (item: any, field: keyof typeof item) => any;
    sortAccessor?: (item: any, field: keyof typeof item) => any;
    groupAccessor?: (item: any, field: keyof typeof item) => any;
    exportTemplate?: (value: any) => string | number;
    template?: (value: any) => ReactNode;
  }
> = {
  number: {
    sortAccessor: (item, field) => Number(item[field]),
    groupAccessor: (item, field) => `#${item[field]}`,
  },
  date: {
    accessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      if (!value) return undefined;
      const date = dayjs(new Date(value as string));
      return date.isValid() ? date : undefined; // .format('D/MMM/YYYY') : 'N/A';
      // return value ? value.format('D/MMM/Y') : 'N/A';
    },
    sortAccessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      return value && new Date(value as string).toISOString().slice(0, 10);
    }, // Remove the timestamp
    groupAccessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      return value && dayjs(new Date(value as string)).format('D/MMM/YYYY');
    },
    exportTemplate: (value) => (value ? value.format('D/MMM/YYYY') : 'N/A'),

    template: (value: dayjs.Dayjs) =>
      value ? value.format('D/MMM/YYYY') : 'N/A',
  },
  datetime: {
    accessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      if (!value) return undefined;
      const date = dayjs(new Date(value as string));
      return date.isValid() ? date : undefined;
    },
    sortAccessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      return value && new Date(value as string);
    },
    groupAccessor: (item, field) => {
      const value = getValueFromPath<{ test: '' }, any>(item, field);
      return value && dayjs(new Date(value as string)).format('D/MMM/YYYY');
    },
    exportTemplate: (value) =>
      value ? value.format('D/MMM/YYYY HH:mm:ss') : 'N/A',
    template: (value) => (value ? value.format('D/MMM/YYYY HH:mm:ss') : 'N/A'),
  },
};

export function getFieldGroupValueFunction<Data extends ObjectLiteral>(
  field: ColumnConfig<Data, never>['field'],
  type: ColumnConfig<Data, never>['type']
): (item: Data) => string {
  let fieldName: Paths<Data>;
  let groupAccessor:
    | object
    | Paths<Data>
    | (typeof typeMap)['']['groupAccessor'] =
    typeMap[type || '']?.groupAccessor;
  if (typeof field === 'object') {
    fieldName = field.field;
    if (field.groupAccessor) groupAccessor = field.groupAccessor;
  } else {
    fieldName = field;
  }
  const accessor = groupAccessor || fieldName;
  return getFieldValueCurried<Data>(accessor, fieldName);
}
export function getFieldSortValueFunction<Data extends ObjectLiteral>(
  field: ColumnConfig<Data, never>['field'],
  type: ColumnConfig<Data, never>['type']
): (item: Data) => number | string {
  let fieldName: Paths<Data>;
  let sortAccessor:
    | object
    | Paths<Data>
    | (typeof typeMap)['']['sortAccessor'] = typeMap[type || '']?.sortAccessor;
  if (typeof field === 'object') {
    fieldName = field.field;
    if (field.sortAccessor) sortAccessor = field.sortAccessor;
  } else {
    fieldName = field;
  }
  return getFieldValueCurried(sortAccessor || fieldName, fieldName);
}

export function ensureArray<T>(
  value: T
): IfAny<
  T,
  T[],
  [T] extends [null] | [undefined]
    ? never[]
    : T extends null | undefined
      ? never
      : T extends unknown[] | readonly unknown[]
        ? T
        : NonNullable<T>[]
> {
  if (value == null) {
    return [] as ReturnType<typeof ensureArray<T>>;
  }
  return (Array.isArray(value) ? value : [value]) as ReturnType<
    typeof ensureArray<T>
  >;
}
