import clsx from 'clsx';
import { DragEventHandler, MouseEventHandler, useRef, useState } from 'react';
import { filterTypes } from '../FilterTypeConfig';
import { QHGridProps } from '../QHGrid';
import { QIcon } from '../components/Icon';
import { getField } from '../selectors/QHGridSelector';
import { ObjectLiteral } from '../types';

interface HeadersProps<Data extends ObjectLiteral, ATI> {
  columns: QHGridProps<Data, ATI>['columns'];
  onColumnReorder?: QHGridProps<Data, ATI>['onColumnReorder'];
  sortBy: QHGridProps<Data, ATI>['sortBy'];
  sortOrder: QHGridProps<Data, ATI>['sortOrder'];
  onSort?: QHGridProps<Data, ATI>['onSort'];
  filters: QHGridProps<Data, ATI>['filters'];
  onFilterUpdate?: QHGridProps<Data, ATI>['onFilterUpdate'];
  rawData?: QHGridProps<Data, ATI>['data'];
  enableDrag?: boolean;
  fetchAsync?: QHGridProps<Data, ATI>['fetchAsync'];
}

export function Headers<Data extends ObjectLiteral, ATI>(
  props: HeadersProps<Data, ATI>
) {
  const enableDrag = props.enableDrag || !!props.onColumnReorder;
  const [dragIndex, setDragIndex] = useState<number>(-1);
  const dragCounts = useRef(new Map<string, number>());
  // const [hoverIndex, setHoverIndex] = useState<number>(-1);
  const handleHeaderDragStart: DragEventHandler<HTMLTableCellElement> = (
    evt
  ) => {
    const { dataset } = evt.currentTarget;
    evt.dataTransfer.setData('colId', dataset.id ?? '');
    setDragIndex(Number(dataset.index));
  };

  const handleHeaderDrop: DragEventHandler<HTMLTableCellElement> = (evt) => {
    setDragIndex(-1);
    const currentTarget = evt.currentTarget;
    currentTarget.classList.remove('qh-drag-hover');
    if (!evt.dataTransfer.getData('colId')) {
      return;
    }
    const index = Number(evt.currentTarget.dataset.index);
    if (Number.isNaN(index) || dragIndex === -1 || dragIndex === index) {
      return;
    }
    props.onColumnReorder?.(dragIndex, index);
  };

  const handleHeaderDragEnd: DragEventHandler<HTMLTableCellElement> = () => {
    setDragIndex(-1);
    dragCounts.current.clear();
  };

  const handleAllowDrop: DragEventHandler<HTMLTableCellElement> = (evt) => {
    if (props.onColumnReorder && evt.dataTransfer.types[0] === 'colid') {
      evt.preventDefault();
      evt.dataTransfer.dropEffect = 'move';
    }
  };

  const handleHeaderDragEnter: DragEventHandler<HTMLTableCellElement> = (
    evt
  ) => {
    if (evt.dataTransfer.types[0] === 'colid') {
      const { dataset } = evt.currentTarget;
      const index = Number(dataset.index);
      evt.currentTarget.style.setProperty(
        '--qh-hover-side',
        String(Math.sign(dragIndex - index))
      );
      evt.currentTarget.classList.add('qh-drag-hover');
      const id = dataset.id!;
      dragCounts.current.set(id, (dragCounts.current.get(id) || 0) + 1);
    }
  };

  const handleHeaderDragLeave: DragEventHandler<HTMLTableCellElement> = (
    evt
  ) => {
    if (evt.dataTransfer.types[0] === 'colid') {
      const id = evt.currentTarget.dataset.id!;
      const count = dragCounts.current
        .set(id, (dragCounts.current.get(id) ?? 0) - 1)
        .get(id);
      if (count) {
        // Still dragging over
        return;
      }
      evt.currentTarget.classList.remove('qh-drag-hover');
    }
  };
  const sortable = !!props.onSort;
  const handleSort: MouseEventHandler<HTMLTableCellElement> = (evt) => {
    const { id } = evt.currentTarget.dataset;
    if (id) {
      props.onSort?.(id);
    }
  };
  const visibleColumns = props.columns
    .map((col, index) => ({ ...col, index }))
    .filter((col) => !col.hidden);
  const columnElements = visibleColumns.map((col) => {
    const field = getField(col.field);
    const { index, id } = col;
    const sortProps: {
      sorted?: 'ascending' | 'descending';
      onClick?: typeof handleSort;
    } = col.sortDisabled
      ? {}
      : {
          sorted:
            props.sortBy === id
              ? props.sortOrder === 'asc'
                ? 'ascending'
                : 'descending'
              : undefined,
          onClick: handleSort,
        };
    const dragProps = enableDrag
      ? {
          'data-id': id,
          'data-index': index,
          draggable: enableDrag,
          onDragStart: handleHeaderDragStart,
          onDrop: handleHeaderDrop,
          onDragEnd: handleHeaderDragEnd,
          onDragOver: handleAllowDrop,
          onDragEnter: handleHeaderDragEnter,
          onDragLeave: handleHeaderDragLeave,
        }
      : {};

    const filterType = col.filterable?.type;
    const filterProps = col.filterable?.props;
    const filterTypeConfig = filterType && filterTypes[filterType];
    const FilterDropdown = filterTypeConfig?.component;

    const filterVals = props.filters[String(field)]?.value;
    return (
      <th
        {...col.headerAttributes}
        className={clsx(col.headerAttributes?.className, { sortable })}
        key={col.id}
        {...sortProps}
        {...dragProps}
      >
        <div>
          {col.title}
          {props.onFilterUpdate && FilterDropdown && (
            <FilterDropdown
              {...filterProps}
              {...filterTypeConfig?.props}
              selectedOpts={filterVals}
              onChange={props.onFilterUpdate(
                getField(col.field) as string,
                filterType
              )}
              data={props.rawData}
              field={getField(col.field)}
              filterType={filterType}
              fetchAsync={props.fetchAsync}
              columnName={col.title}
              columnId={col.id}
            />
          )}
          <QIcon
            className={clsx('qhSortIcon', {
              qhHidden: props.sortBy !== id,
            })}
            name={`sort`}
          />
        </div>
      </th>
    );
  });
  return <>{columnElements}</>;
}
